class CifarLoader:
    def __init__(self, path, train=True, batch_size=500, aug=None):
        from pathlib import Path

        data_path = Path(path) / ("train.pt" if train else "test.pt")
        if not data_path.exists():
            dset = torchvision.datasets.CIFAR10(path, download=True, train=train)
            images = torch.tensor(dset.data)
            labels = torch.tensor(dset.targets)
            torch.save({"images": images, "labels": labels, "classes": dset.classes}, data_path)

        data = torch.load(data_path, map_location=torch.device("cuda"))
        self.images, self.labels, self.classes = data["images"], data["labels"], data["classes"]
        self.images = (self.images.half() / 255).permute(0, 3, 1, 2).to(memory_format=torch.channels_last)

        self.normalize = T.Normalize(CIFAR_MEAN, CIFAR_STD)
        self.batch_size = batch_size
        self.shuffle = train
        self.aug = aug or {}
        self.pad = self.aug.get("translate", 0)
        self.do_flip = self.aug.get("flip", False)

    def __len__(self):
        return ceil(len(self.images) / self.batch_size)

    def __iter__(self):
        indices = (torch.randperm if self.shuffle else torch.arange)(len(self.images), device=self.images.device)

        for i in range(len(self)):
            idxs = indices[i * self.batch_size : (i + 1) * self.batch_size]
            batch = self.images[idxs]

            if self.do_flip and torch.rand(1) > 0.5:
                batch = batch.flip(-1)

            if self.pad > 0:
                batch = F.pad(batch, (self.pad,) * 4, "reflect")
                batch = batch_crop(batch, self.images.shape[-2])

            yield self.normalize(batch), self.labels[idxs]
